<template>
  <div>
    <input type="button" id="" value="扫描二维码" @click="executeGoToScanPager()" />
  </div>
</template>

<script>
export default {
  name: 'hmx', // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
   return {
    dataProps: ''
   }
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //到扫描界面
	 executeGoToScanPager(){
    	
    	if(!ready){    		
    		return;
    	}
		alert("00");
    	//执行到这边表示cordova环境准备完成,在二维码扫描界面
    	mam.navigator.forward.goToScanTwoDiemCode(successCallback,errorCallback);
    	//执行成功回调
    	//这边参数表示扫描成功后返回的字符串
    	function successCallback(msg){    		
			alert("11");
    		document.getElementById('textarea').value = msg;
       }    	
    	//执行失败回调[扫描失败，暂不退出界面未做处理]
    	function errorCallback(msg){
    		alert("11");
			document.getElementById("list").innerHTML = "";
    	} 
    }
  }
}
</script>
